input_schema:
{
  "schemaVersion": 1,
  "title": "stepstone-de-scraper Input",
  "type": "object",
  "properties": {
    "searchQuery": {
      "type": "string",
      "editor": "textfield",
      "default": "",
      "description": "searchQuery.",
      "title": "Search Query"
    },
    "location": {
      "type": "string",
      "editor": "textfield",
      "default": "",
      "description": "location.",
      "title": "Location"
    },
    "radius": {
      "type": "integer",
      "editor": "number",
      "default": 40,
      "minimum": 0,
      "description": "Numeric filter: radius.",
      "title": "Radius"
    },
    "maxItems": {
      "type": "integer",
      "editor": "number",
      "default": 5,
      "minimum": 0,
      "description": "Maximum number of results (0 = no limit).",
      "title": "Max Items"
    },
    "daysOld": {
      "type": "integer",
      "editor": "number",
      "description": "Only return items published within the last N days. Leave blank for all.",
      "minimum": 1,
      "title": "Days Old"
    },
    "skipReposts": {
      "type": "boolean",
      "default": false,
      "description": "Enable skipReposts.",
      "title": "Skip Reposts"
    },
    "startUrls": {
      "type": "array",
      "editor": "json",
      "items": {
        "type": "string"
      },
      "default": [],
      "description": "Filter by startUrls.",
      "title": "Start Urls"
    }
  }
}
